import { createLinterRuleTester, LinterRuleTester } from "@typespec/compiler/testing";
import { beforeEach, describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";
import { systemProseRefsRule } from "./system-prose-refs.rule.js";

const ENTITY = `
  namespace Products.MyProduct.Entities.Task {
    @entity
    model Task { id: string; status: TaskStatus; }
    enum TaskStatus { pending, running }
  }
  using Products.MyProduct.Entities.Task;
`;

describe("system-prose-refs rule", () => {
  let ruleTester: LinterRuleTester;

  beforeEach(async () => {
    const runner = await Tester.createInstance();
    ruleTester = createLinterRuleTester(runner, systemProseRefsRule, "@a10n/blueprint-typespec");
  });

  describe("valid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T008.T008_01
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_system_prose_refs:Products.A10nBlueprintEngine.Features.SystemAuthoring.prose_refs_system:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_worker_type_spec:Products.A10nBlueprintEngine.Features.SystemAuthoring.prose_refs_system:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_system_prose_refs:Products.A10nBlueprintEngine.Features.TwoLayerArchitecture.domain_no_sys:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_worker_type_spec:Products.A10nBlueprintEngine.Features.TwoLayerArchitecture.domain_no_sys:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_system_prose_refs
    it("@doc referencing a system-layer model — allowed", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Service })
          namespace Components.MyApiService {
            model TaskRow { id: string; }

            @doc("Processes a {@TaskRow} record.")
            @flow
            op process_task(): void;
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T008.T008_02
    it("@doc referencing an enum value from an entity file — allowed", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}

          @component(#{ type: ComponentType.Service })
          namespace Components.MyApiService {
            @doc("Sets status to {@TaskStatus.running}.")
            @flow
            op run_task(): void;
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T008.T008_05
    it("@signal criteria referencing an enum value — allowed", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}

          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            @eval(#{ title: "e" })
            namespace Evals.Lifecycle.E001 {
              @signal(#{
                title: "s",
                method: SignalMethod.Deterministic,
                criteria: "Set status to {@TaskStatus.running}",
                examples: #[],
              })
              op E001_01(): boolean;
            }
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T008.T008_06
    it("@testing reasoning referencing a system component — allowed", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Service })
          namespace Components.DepAService {}

          @component(#{ type: ComponentType.Agent })
          @testing(Components.DepAService, #{
            approach: TestingApproach.Mock,
            reasoning: "Use a fake {@Components.DepAService} to avoid live calls.",
          })
          namespace Components.MyAgent {}
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T008.T008_07
    it("domain entity refs in @feature @doc — allowed (feature is domain layer)", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}

          @feature
          namespace Products.MyProduct.Features.Lifecycle {
            @invariant(#{
              predicate: "A {@Task} has an id.",
              why: "Reason referencing {@Task.id}.",
            })
            op task_has_id(): void;
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T008.T008_08
    it("@signal criteria + nested example descriptions, all enum values — allowed", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}

          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            @eval(#{ title: "e" })
            namespace Evals.Lifecycle.E001 {
              @signal(#{
                title: "s",
                method: SignalMethod.Deterministic,
                criteria: "Transition to {@TaskStatus.running} from {@TaskStatus.pending}.",
                examples: #[
                  #{ value: true, description: "Status is {@TaskStatus.running}" },
                  #{ value: false, description: "Status is {@TaskStatus.pending}" },
                ],
              })
              op E001_01(): boolean;
            }
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T008.T008_09
    it("@signal examples with enum values in description — allowed", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}

          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            @eval(#{ title: "e" })
            namespace Evals.Lifecycle.E001 {
              @signal(#{
                title: "s",
                method: SignalMethod.Deterministic,
                criteria: "Is status {@TaskStatus.running}?",
                examples: #[
                  #{ value: true, description: "Status is {@TaskStatus.running}" },
                  #{ value: false, description: "Status is {@TaskStatus.pending}" },
                ],
              })
              op E001_01(): boolean;
            }
          }
        `)
        .toBeValid();
    });
  });

  describe("invalid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T008.T008_03
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_system_prose_refs:Products.A10nBlueprintEngine.Features.TwoLayerArchitecture.domain_no_sys:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_system_prose_refs
    it("@doc on component @flow op referencing an @entity model", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}

          @component(#{ type: ComponentType.Service })
          namespace Components.MyApiService {
            @doc("Processes a {@Task} to completion.")
            @flow
            op process_task(): void;
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/system-prose-refs",
          message: /Task/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T008.T008_10
    it("@doc on component namespace itself referencing an @entity model", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}

          @doc("Manages {@Task} lifecycle.")
          @component(#{ type: ComponentType.Service })
          namespace Components.MyApiService {}
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/system-prose-refs",
          message: /Task/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T008.T008_04
    it("@signal criteria referencing an @entity model field", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}

          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            @eval(#{ title: "e" })
            namespace Evals.Lifecycle.E001 {
              @signal(#{
                title: "s",
                method: SignalMethod.Deterministic,
                criteria: "Set {@Task.id} to new value",
                examples: #[],
              })
              op E001_01(): boolean;
            }
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/system-prose-refs",
          message: /Task\.id/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T008.T008_11
    it("@signal criteria referencing an @entity model", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}

          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            @eval(#{ title: "e" })
            namespace Evals.Lifecycle.E001 {
              @signal(#{
                title: "s",
                method: SignalMethod.Probabilistic,
                criteria: "Does the {@Task} get processed?",
                examples: #[],
              })
              op E001_01(): boolean;
            }
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/system-prose-refs",
          message: /Task/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T008.T008_12
    it("@signal criteria + multiple nested example descriptions — entity refs in all string fields fire", async () => {
      // The rule walks all string values in all decorator args recursively.
      // Every nested string field must be checked, not just the top-level one.
      await ruleTester
        .expect(`
          ${ENTITY}

          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            @eval(#{ title: "e" })
            namespace Evals.Lifecycle.E001 {
              @signal(#{
                title: "s",
                method: SignalMethod.Deterministic,
                criteria: "Create a {@Task} record",
                examples: #[
                  #{ value: true, description: "A {@Task} was created" },
                  #{ value: false, description: "Covers {@Task.id} assignment" },
                ],
              })
              op E001_01(): boolean;
            }
          }
        `)
        .toEmitDiagnostics([
          { code: "@a10n/blueprint-typespec/system-prose-refs", message: /Task/ },
          { code: "@a10n/blueprint-typespec/system-prose-refs", message: /Task/ },
          { code: "@a10n/blueprint-typespec/system-prose-refs", message: /Task/ },
        ]);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T008.T008_13
    it("@signal examples.description referencing an entity model — fires", async () => {
      // The rule recurses into ObjectValue.properties so nested description strings are checked.
      await ruleTester
        .expect(`
          ${ENTITY}

          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            @eval(#{ title: "e" })
            namespace Evals.Lifecycle.E001 {
              @signal(#{
                title: "s",
                method: SignalMethod.Probabilistic,
                criteria: "criteria",
                examples: #[
                  #{ value: true, description: "A {@Task} was processed correctly" },
                ],
              })
              op E001_01(): boolean;
            }
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/system-prose-refs",
          message: /Task/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T008.T008_14
    it("@doc on a model field inside @component — fires", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}

          @component(#{ type: ComponentType.Service })
          namespace Components.MyApiService {
            model TaskRow {
              @doc("Mirrors the {@Task.id} from the domain entity.")
              id: string;
            }
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/system-prose-refs",
          message: /Task\.id/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T008.T008_15
    it("entity field ref ({@Task.id}) fires same as entity model ref ({@Task})", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}

          @component(#{ type: ComponentType.Service })
          namespace Components.MyApiService {
            @doc("Stores the {@Task.id} value.")
            @flow
            op store_id(): void;
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/system-prose-refs",
          message: /Task\.id/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T008.T008_16
    it("@testing reasoning referencing an @entity model", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}

          @component(#{ type: ComponentType.Service })
          namespace Components.DepAService {}

          @component(#{ type: ComponentType.Agent })
          @testing(Components.DepAService, #{
            approach: TestingApproach.Mock,
            reasoning: "Fake dep so {@Task} entities are not created.",
          })
          namespace Components.MyAgent {}
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/system-prose-refs",
          message: /Task/,
        });
    });
  });

  // ── pred_no_sys: @invariant predicate must not ref system-layer constructs ──

  describe("valid — invariant predicate system-layer refs (pred_no_sys)", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T008.T008_17
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_system_prose_refs:Products.A10nBlueprintEngine.Features.DomainAuthoring.pred_no_sys:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_worker_type_spec:Products.A10nBlueprintEngine.Features.DomainAuthoring.pred_no_sys:must
    it("@invariant predicate referencing a domain entity — allowed", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}

          @feature
          namespace Products.MyProduct.Features.Lifecycle {
            @invariant(#{
              predicate: "A {@Task} has a non-empty {@Task.id}.",
              why: "Reason.",
            })
            op task_has_id(): void;
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T008.T008_18
    it("@invariant predicate referencing a domain enum value — allowed", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}

          @feature
          namespace Products.MyProduct.Features.Lifecycle {
            @invariant(#{
              predicate: "Status is always {@TaskStatus.running} after start.",
              why: "Reason.",
            })
            op status_running(): void;
          }
        `)
        .toBeValid();
    });
  });

  describe("valid — invariant predicate refs to plain models/enums inside @component (pred_no_sys)", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T008.T008_21
    it("@invariant predicate referencing a plain model inside @component — allowed (data type, not op)", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Service })
          namespace Components.MyApiService {
            model TaskRow { id: string; label: string; }
          }

          using Components.MyApiService;

          @feature
          namespace Products.MyProduct.Features.Lifecycle {
            @invariant(#{
              predicate: "Every {@TaskRow} has a label.",
              why: "TaskRow is a data model; allowed in invariant predicates.",
            })
            op row_has_label(): void;
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T008.T008_22
    it("@invariant predicate referencing a field of a plain model inside @component — allowed", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Service })
          namespace Components.MyApiService {
            model TaskRow { id: string; label: string; }
          }

          using Components.MyApiService;

          @feature
          namespace Products.MyProduct.Features.Lifecycle {
            @invariant(#{
              predicate: "The {@TaskRow.id} is always non-empty.",
              why: "TaskRow.id is a data field; allowed in invariant predicates.",
            })
            op row_id_set(): void;
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T008.T008_23
    it("@invariant predicate referencing an enum inside @component — allowed (plain data enum)", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Service })
          namespace Components.MyApiService {
            enum Priority { low, high }
          }

          using Components.MyApiService;

          @feature
          namespace Products.MyProduct.Features.Lifecycle {
            @invariant(#{
              predicate: "A task with {@Priority.high} is first.",
              why: "Priority is an enum data type; allowed in invariant predicates.",
            })
            op high_first(): void;
          }
        `)
        .toBeValid();
    });
  });

  describe("invalid — invariant predicate system-layer refs (pred_no_sys)", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T008.T008_19
    it("@invariant predicate referencing a @component namespace — reports invariant-pred-system-ref", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}

          @component(#{ type: ComponentType.Service })
          namespace Components.MyApiService {}

          @feature
          namespace Products.MyProduct.Features.Lifecycle {
            @invariant(#{
              predicate: "The {@Components.MyApiService} always responds.",
              why: "Reason.",
            })
            op service_responds(): void;
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/system-prose-refs",
          message: /Components\.MyApiService/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T008.T008_20
    it("@invariant predicate referencing a component op (@flow) — reports invariant-pred-system-ref", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}

          @component(#{ type: ComponentType.Service })
          namespace Components.MyApiService {
            @flow
            op process_task(): void;
          }

          @feature
          namespace Products.MyProduct.Features.Lifecycle {
            @invariant(#{
              predicate: "Calling {@Components.MyApiService.process_task} sets status.",
              why: "Reason.",
            })
            op process_sets_status(): void;
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/system-prose-refs",
          message: /process_task/,
        });
    });
  });
});
